// MARK: - Token Storage

protocol TokenStorage {
    func saveTokens(_ tokens: AuthTokens)
    func getAccessToken() -> String?
    func getRefreshToken() -> String?
    func clearTokens()
}

final class KeychainTokenStorage: TokenStorage {
    
    static let shared = KeychainTokenStorage()
    
    private let accessTokenKey = "com.example.app.accessToken"
    private let refreshTokenKey = "com.example.app.refreshToken"
    
    private init() {}
    
    func saveTokens(_ tokens: AuthTokens) {
        save(key: accessTokenKey, value: tokens.accessToken)
        save(key: refreshTokenKey, value: tokens.refreshToken)
    }
    
    func getAccessToken() -> String? {
        return load(key: accessTokenKey)
    }
    
    func getRefreshToken() -> String? {
        return load(key: refreshTokenKey)
    }
    
    func clearTokens() {
        delete(key: accessTokenKey)
        delete(key: refreshTokenKey)
    }
    
    // MARK: - Keychain Helpers
    
    private func save(key: String, value: String) {
        guard let data = value.data(using: .utf8) else { return }
        
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrAccount as String: key
        ]
        SecItemDelete(query as CFDictionary)
        
        let attributes: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrAccount as String: key,
            kSecValueData as String: data,
            kSecAttrAccessible as String: kSecAttrAccessibleAfterFirstUnlockThisDeviceOnly
        ]
        SecItemAdd(attributes as CFDictionary, nil)
    }
    
    private func load(key: String) -> String? {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrAccount as String: key,
            kSecReturnData as String: true,
            kSecMatchLimit as String: kSecMatchLimitOne
        ]
        
        var result: AnyObject?
        let status = SecItemCopyMatching(query as CFDictionary, &result)
        
        guard status == errSecSuccess, let data = result as? Data else {
            return nil
        }
        return String(data: data, encoding: .utf8)
    }
    
    private func delete(key: String) {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrAccount as String: key
        ]
        SecItemDelete(query as CFDictionary)
    }
}

// MARK: - Network Client

protocol NetworkClientProtocol {
    func request<T: Decodable>(endpoint: APIEndpoint, body: Encodable?, queryParams: [String: String]?) async throws -> T
}

final class NetworkClient: NetworkClientProtocol {
    
    static let shared = NetworkClient()
    
    private let session: URLSession
    private let environment: Environment
    private let tokenStorage: TokenStorage
    private let encoder: JSONEncoder
    private let decoder: JSONDecoder
    
    private var isRefreshing = false
    private var refreshContinuations: [CheckedContinuation<Void, Error>] = []
    private let refreshLock = NSLock()
    
    init(
        environment: Environment = .development, // Change for your build config
        tokenStorage: TokenStorage = KeychainTokenStorage.shared,
        sessionConfiguration: URLSessionConfiguration = .default
    ) {
        self.environment = environment
        self.tokenStorage = tokenStorage
        
        sessionConfiguration.timeoutIntervalForRequest = 30
        sessionConfiguration.timeoutIntervalForResource = 60
        sessionConfiguration.waitsForConnectivity = true
        
        self.session = URLSession(configuration: sessionConfiguration)
        
        self.encoder = JSONEncoder()
        self.decoder = JSONDecoder()
    }
    
    // MARK: - Public Request Method
    
    func request<T: Decodable>(
        endpoint: APIEndpoint,
        body: Encodable? = nil,
        queryParams: [String: String]? = nil
    ) async throws -> T {
        let urlRequest = try buildRequest(endpoint: endpoint, body: body, queryParams: queryParams)
        return try await executeRequest(urlRequest, endpoint: endpoint, body: body, queryParams: queryParams)
    }
    
    // MARK: - Private Helpers
    
    private func buildRequest(
        endpoint: APIEndpoint,
        body: Encodable?,
        queryParams: [String: String]?
    ) throws -> URLRequest {
        var urlString = environment.baseURL + endpoint.path
        
        if let queryParams = queryParams, !queryParams.isEmpty {
            var components = URLComponents(string: urlString)
            components?.queryItems = queryParams.map { URLQueryItem(name: $0.key, value: $0.value) }
            if let updatedURL = components?.string {
                urlString = updatedURL
            }
        }
        
        guard let url = URL(string: urlString) else {
            throw NetworkError.invalidURL
        }
        
        var request = URLRequest(url: url)
        request.httpMethod = endpoint.method.rawValue
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        request.setValue("application/json", forHTTPHeaderField: "Accept")
        
        // Attach auth token for non-auth endpoints
        if !isAuthEndpoint(endpoint), let token = tokenStorage.getAccessToken() {
            request.setValue("Bearer \(token)", forHTTPHeaderField: "Authorization")
        }
        
        if let body = body {
            request.httpBody = try encoder.encode(AnyEncodable(body))
        }
        
        return request
    }
    
    private func executeRequest<T: Decodable>(
        _ request: URLRequest,
        endpoint: APIEndpoint,
        body: Encodable?,
        queryParams: [String: String]?,
        isRetry: Bool = false
    ) async throws -> T {
        let data: Data
        let response: URLResponse
        
        do {
            (data, response) = try await session.data(for: request)
        } catch {
            throw NetworkError.networkFailure(error)
        }
        
        guard let httpResponse = response as? HTTPURLResponse else {
            throw NetworkError.unknown
        }
        
        #if DEBUG
        logRequest(request, response: httpResponse, data: data)
        #endif
        
        switch httpResponse.statusCode {
        case 200...299:
            do {
                let decoded = try decoder.decode(T.self, from: data)
                return decoded
            } catch {
                throw NetworkError.decodingError(error)
            }
            
        case 401:
            if !isRetry && !isAuthEndpoint(endpoint) {
                try await refreshTokenIfNeeded()
                let newRequest = try buildRequest(endpoint: endpoint, body: body, queryParams: queryParams)
                return try await executeRequest(newRequest, endpoint: endpoint, body: body, queryParams: queryParams, isRetry: true)
            }
            throw NetworkError.unauthorized
            
        default:
            let errorMessage = try? decoder.decode(APIErrorResponse.self, from: data)
            throw NetworkError.serverError(statusCode: httpResponse.statusCode, message: errorMessage?.message)
        }
    }
    
    private func isAuthEndpoint(_ endpoint: APIEndpoint) -> Bool {
        switch endpoint {
        case .login, .register, .refreshToken:
            return true
        default:
            return false
        }
    }
    
    // MARK: - Token Refresh
    
    private func refreshTokenIfNeeded() async throws {
        refreshLock.lock()
        
        if isRefreshing {
            refreshLock.unlock()
            // Wait for the ongoing refresh to complete
            try await withCheckedThrowingContinuation { (continuation: CheckedContinuation<Void, Error>) in
                refreshLock.lock()
                refreshContinuations.append(continuation)
                refreshLock.unlock()
            }
            return
        }
        
        isRefreshing = true
        refreshLock.unlock()
        
        defer {
            refreshLock.lock()
            isRefreshing = false
            let continuations = refreshContinuations
            refreshContinuations.removeAll()
            refreshLock.unlock()
            
            for continuation in continuations {
                continuation.resume()
            }
        }
        
        guard let refreshToken = tokenStorage.getRefreshToken() else {
            throw NetworkError.unauthorized
        }
        
        let body = ["refresh_token": refreshToken]
        let urlString = environment.baseURL + APIEndpoint.refreshToken.path
        
        guard let url = URL(string: urlString) else {
            throw NetworkError.invalidURL
        }
        
        var request = URLRequest(url: url)
        request.httpMethod = HTTPMethod.post.rawValue
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        request.httpBody = try encoder.encode(body)
        
        let (data, response) = try await session.data(for: request)
        
        guard let httpResponse = response as? HTTPURLResponse, httpResponse.statusCode == 200 else {
            tokenStorage.clearTokens()
            throw NetworkError.unauthorized
        }
        
        let tokens = try decoder.decode(AuthTokens.self, from: data)
        tokenStorage.saveTokens(tokens)
    }
    
    // MARK: - Logging
    
    private func logRequest(_ request: URLRequest, response: HTTPURLResponse, data: Data) {
        print("🌐 [\(request.httpMethod ?? "")] \(request.url?.absoluteString ?? "")")
        print("📊 Status: \(response.statusCode)")
        if let bodyString = String(data: data, encoding: .utf8) {
            print("📦 Response: \(bodyString.prefix(500))")
        }
    }
}

// MARK: - AnyEncodable Helper

struct AnyEncodable: Encodable {
    private let _encode: (Encoder) throws -> Void
    
    init(_ wrapped: Encodable) {
        _encode = wrapped.encode
    }
    
    func encode(to encoder: Encoder) throws {
        try _encode(encoder)
    }
}

